#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
#define MAX_NAME 10

// Define a structure to represent a station
typedef struct {
    char name[MAX_NAME];
    int lines[MAX];
    int numLines;
} Station;

// Define a structure to represent a graph
typedef struct {
    Station stations[MAX];
    int numStations;
} Graph;

// Function to add a station to the graph
void addStation(Graph *graph, char *name) {
    strcpy(graph->stations[graph->numStations].name, name);
    graph->stations[graph->numStations].numLines = 0;
    graph->numStations++;
}

// Function to add a line to a station
void addLine(Graph *graph, char *stationName, int line) {
    for (int i = 0; i < graph->numStations; i++) {
        if (strcmp(graph->stations[i].name, stationName) == 0) {
            graph->stations[i].lines[graph->stations[i].numLines] = line;
            graph->stations[i].numLines++;
            return;
        }
    }
}

// Function to find the shortest path between two stations
int shortestPath(Graph *graph, char *start, char *end) {
    int visited[MAX] = {0};
    int queue[MAX];
    int front = 0, rear = 0;
    int distance[MAX] = {0};

    // Find the start station and add it to the queue
    for (int i = 0; i < graph->numStations; i++) {
        if (strcmp(graph->stations[i].name, start) == 0) {
            queue[rear] = i;
            visited[i] = 1;
            distance[i] = 0;
            rear++;
            break;
        }
    }

    while (front < rear) {
        int current = queue[front];
        front++;

        // Check all neighboring stations
        for (int i = 0; i < graph->stations[current].numLines; i++) {
            for (int j = 0; j < graph->numStations; j++) {
                if (graph->stations[j].lines[i] == graph->stations[current].lines[i] && !visited[j]) {
                    queue[rear] = j;
                    visited[j] = 1;
                    distance[j] = distance[current] + 1;
                    rear++;

                    // If we found the end station, return the distance
                    if (strcmp(graph->stations[j].name, end) == 0) {
                        return distance[j];
                    }
                }
            }
        }
    }

    // If we didn't find the end station, return -1
    return -1;
}

int main() {
    Graph graph;
    graph.numStations = 0;

    int n;
    scanf("%d", &n);

    for (int i = 0; i < n; i++) {
        char name[MAX_NAME];
        scanf("%s", name);
        addStation(&graph, name);
    }

    int m;
    scanf("%d", &m);

    for (int i = 0; i < m; i++) {
        char start[MAX_NAME], end[MAX_NAME];
        scanf("%s %s", start, end);
        printf("%d\n", shortestPath(&graph, start, end));
    }

    return 0;
}

