#include <string>
#include <unordered_map>
using namespace std;

// Define a structure to represent a station
struct Station {
    string name;
    vector<int> lines;
};

// Define a structure to represent a graph
struct Graph {
    vector<Station> stations;
    unordered_map<string, int> stationMap;
};

// Function to add a station to the graph
void addStation(Graph &graph, string name) {
    Station station;
    station.name = name;
    graph.stations.push_back(station);
    graph.stationMap[name] = graph.stations.size() - 1;
}

// Function to add a line to a station
void addLine(Graph &graph, string stationName, int line) {
    graph.stations[graph.stationMap[stationName]].lines.push_back(line);
}

// Function to find the shortest path between two stations
int shortestPath(Graph &graph, string start, string end) {
    vector<bool> visited(graph.stations.size(), false);
    queue<int> q;
    vector<int> distance(graph.stations.size(), 0);

    // Find the start station and add it to the queue
    q.push(graph.stationMap[start]);
    visited[graph.stationMap[start]] = true;
    distance[graph.stationMap[start]] = 0;

    while (!q.empty()) {
        int current = q.front();
        q.pop();

        // Check all neighboring stations
        for (int i = 0; i < graph.stations[current].lines.size(); i++) {
            for (int j = 0; j < graph.stations.size(); j++) {
                if (find(graph.stations[j].lines.begin(), graph.stations[j].lines.end(), graph.stations[current].lines[i]) != graph.stations[j].lines.end() && !visited[j]) {
                    q.push(j);
                    visited[j] = true;
                    distance[j] = distance[current] + 1;

                    // If we found the end station, return the distance
                    if (graph.stations[j].name == end) {
                        return distance[j];
                    }
                }
            }
        }
    }

    // If we didn't find the end station, return -1
    return -1;
}

int main() {
    Graph graph;

    int n;
    cin >> n;

    for (int i = 0; i < n; i++) {
        string name;
        cin >> name;
        addStation(graph, name);
    }

    int m;
    cin >> m;

    for (int i = 0; i < m; i++) {
        string start, end;
        cin >> start >> end;
        cout << shortestPath(graph, start, end) << endl;
    }

    return 0;
}

