import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
import java.util.HashMap;
import java.util.Map;

// Define a class to represent a station
class Station {
    String name;
    int[] lines;
    int numLines;

    public Station(String name) {
        this.name = name;
        this.lines = new int[10];
        this.numLines = 0;
    }
}

// Define a class to represent a graph
class Graph {
    Station[] stations;
    Map<String, Integer> stationMap;
    int numStations;

    public Graph(int numStations) {
        this.numStations = numStations;
        this.stations = new Station[numStations];
        this.stationMap = new HashMap<>();
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        Graph graph = new Graph(n);

        for (int i = 0; i < n; i++) {
            String name = scanner.next();
            graph.stations[i] = new Station(name);
            graph.stationMap.put(name, i);
        }

        int m = scanner.nextInt();

        for (int i = 0; i < m; i++) {
            String start = scanner.next();
            String end = scanner.next();
            System.out.println(shortestPath(graph, start, end));
        }
    }

    public static int shortestPath(Graph graph, String start, String end) {
        boolean[] visited = new boolean[graph.numStations];
        Queue<Integer> queue = new LinkedList<>();
        int[] distance = new int[graph.numStations];

        // Find the start station and add it to the queue
        queue.add(graph.stationMap.get(start));
        visited[graph.stationMap.get(start)] = true;
        distance[graph.stationMap.get(start)] = 0;

        while (!queue.isEmpty()) {
            int current = queue.poll();

            // Check all neighboring stations
            for (int i = 0; i < graph.stations[current].numLines; i++) {
                for (int j = 0; j < graph.numStations; j++) {
                    if (graph.stations[j].lines[i] == graph.stations[current].lines[i] && !visited[j]) {
                        queue.add(j);
                        visited[j] = true;
                        distance[j] = distance[current] + 1;

                        // If we found the end station, return the distance
                        if (graph.stations[j].name.equals(end)) {
                            return distance[j];
                        }
                    }
                }
            }
        }

        // If we didn't find the end station, return -1
        return -1;
    }
}

