const readline = require('readline');

// Define a class to represent a station
class Station {
    constructor(name) {
        this.name = name;
        this.lines = [];
    }
}

// Define a class to represent a graph
class Graph {
    constructor(numStations) {
        this.stations = new Array(numStations);
        this.stationMap = new Map();
        this.numStations = numStations;
    }

    addStation(name) {
        for (let i = 0; i < this.numStations; i++) {
            if (this.stations[i] === undefined) {
                this.stations[i] = new Station(name);
                this.stationMap.set(name, i);
                break;
            }
        }
    }

    addLine(stationName, line) {
        this.stations[this.stationMap.get(stationName)].lines.push(line);
    }

    shortestPath(start, end) {
        const visited = new Array(this.numStations).fill(false);
        const queue = [];
        const distance = new Array(this.numStations).fill(0);

        // Find the start station and add it to the queue
        queue.push(this.stationMap.get(start));
        visited[this.stationMap.get(start)] = true;
        distance[this.stationMap.get(start)] = 0;

        while (queue.length > 0) {
            const current = queue.shift();

            // Check all neighboring stations
            for (let i = 0; i < this.stations[current].lines.length; i++) {
                for (let j = 0; j < this.numStations; j++) {
                    if (this.stations[j].lines.includes(this.stations[current].lines[i]) && !visited[j]) {
                        queue.push(j);
                        visited[j] = true;
                        distance[j] = distance[current] + 1;

                        // If we found the end station, return the distance
                        if (this.stations[j].name === end) {
                            return distance[j];
                        }
                    }
                }
            }
        }

        // If we didn't find the end station, return -1
        return -1;
    }
}

